102→const decorateNotificationMedia = (notification) => {
103→    if(!notification || typeof notification !== 'object'){
104→        return notification;
105→    }
106→
107→    const senderAvatarMedia = createMediaResponsePayload('avatars', notification.users?.image_url, 'card');
108→    const journalThumbnailMedia = createMediaResponsePayload('journal-images', notification.journals?.thumbnail_url, 'card');
109→    const journalUserAvatarMedia = createMediaResponsePayload('avatars', notification.journals?.users?.image_url, 'card');
110→
111→    return {
112→        ...notification,
113→        users: notification.users ? {
114→            ...notification.users,
115→            image_url: senderAvatarMedia?.preferred_url || notification.users.image_url || null,
116→            avatar_media: senderAvatarMedia
117→        } : notification.users,
118→        journals: notification.journals ? {
119→            ...notification.journals,
120→            thumbnail_url: journalThumbnailMedia?.preferred_url || notification.journals.thumbnail_url || null,
121→            thumbnail_media: journalThumbnailMedia,
122→            users: notification.journals.users ? {
123→                ...notification.journals.users,
