131→const parseLimitWithinRange = (value, min, max, fallback = null) => {
132→    const parsed = Number.parseInt(value, 10);
133→    if (Number.isNaN(parsed)) {
134→        return fallback;
135→    }
136→    if (parsed < min || parsed > max) {
137→        return null;
138→    }
139→    return parsed;
140→};
