205→router.get('/getFollowsData', async(req, res) => {
206→    const {userId, loggedInUserId} = req.query;
207→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggedInUserId is undefined '});
208→    // console.log(req.query)
209→    try {
210→        const followersCountPromise = supabase
211→        .from('follows')
212→        .select('id', {count: 'exact', head: true})
213→        .eq('following_id', userId);
214→
215→        const followingCountPromise = supabase
216→        .from('follows')
217→        .select('id', {count: 'exact', head: true})
218→        .eq('follower_id', userId)
219→
220→        const isFollowingPromise = supabase
221→        .from('follows')
222→        .select('id', {count: 'exact', head: true})
223→        .eq('follower_id', loggedInUserId)
224→        .eq('following_id', userId)
225→
226→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
227→            followersCountPromise, followingCountPromise, isFollowingPromise,
228→        ])
229→
230→
231→        const {count: followersCount, error: errorFollowers } = followersCountResult;
232→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
233→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
234→
235→        if(errorFollowers || errorFollowings || errorIsfollowing){
236→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
237→            return res.status(500).json({error: 'failed to fetch data'})
238→        }
239→
240→        return res.status(200).json({
241→            followersCount: followersCount,
242→            followingsCount: followingsCount,
243→            isFollowing: isFollowingCount > 0
244→        })
245→
246→    } catch (error) {
247→        console.error('Error in Promise.all:', error);
248→        res.status(500).json({ error: 'An unexpected error occurred' });
249→    }
250→
251→})
