278→router.get('/getNotifications', requireAuth, async(req, res) =>{
279→    const {before} = req.query;
280→    const userId = req.userId;
281→    const parsedLimit = parseLimitWithinRange(
282→        req.query.limit,
283→        NOTIFICATION_LIMIT_MIN,
284→        NOTIFICATION_LIMIT_MAX,
285→        NOTIFICATION_DEFAULT_LIMIT
286→    );
287→
288→    if(parsedLimit == null){
289→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
290→    }
291→
292→    // Fetch a generous amount from both tables, then merge and paginate
293→    const fetchLimit = parsedLimit + 1;
294→
295→    let journalQuery = supabase
296→    .from('notifications')
297→    .select(NOTIFICATION_JOURNAL_SELECT)
298→    .eq('receiver_id', userId)
299→    .order('created_at', {ascending: false})
300→    .order('id', {ascending: false})
301→    .limit(fetchLimit)
302→
303→    let opinionQuery = supabase
304→    .from('notification_opinions')
305→    .select(NOTIFICATION_OPINION_SELECT)
306→    .eq('receiver_id', userId)
307→    .order('created_at', {ascending: false})
308→    .order('id', {ascending: false})
309→    .limit(fetchLimit)
310→
311→    if(before){
312→        journalQuery = journalQuery.lt('created_at', before);
313→        opinionQuery = opinionQuery.lt('created_at', before);
314→    }
315→
316→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
317→
318→    if(journalResult.error){
319→        console.error('error while fetching data from notification table:', journalResult.error);
320→        return res.status(500).json({error: 'error fetching data from notification table'});
321→    }
322→    if(opinionResult.error){
323→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
324→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
325→    }
326→
327→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
328→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
329→
330→    // Merge and sort by created_at descending
331→    const merged = [...journalNotifs, ...opinionNotifs]
332→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
333→
334→    // Likes/bookmarks lookup only for journal notifications
335→    const journalIds = [...new Set(
336→        merged
337→            .filter((n) => n.source === 'journal')
338→            .map((n) => n.journal_id)
339→            .filter(Boolean)
340→    )];
341→
342→    let hasLikedResult = [];
343→    let hasBookMarkedResult = [];
344→    if(journalIds.length > 0){
345→        const [hasLiked, hasBookMarked] = await Promise.all([
346→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
347→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
348→        ]);
349→
350→        if(hasLiked.error || hasBookMarked.error){
351→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
352→        }
353→        hasLikedResult = hasLiked.data || [];
354→        hasBookMarkedResult = hasBookMarked.data || [];
355→    }
356→
357→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
358→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
359→
360→    const formatted = merged.map((notif) => decorateNotificationMedia({
361→        ...notif,
362→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
363→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
364→    }))
365→
366→    const hasMore = formatted.length > parsedLimit;
367→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
368→
369→    return res.status(200).json(
370→        {
371→            hasMore: hasMore,
372→            data: slicedData,
373→        }
374→    )
375→
376→})
