853→router.post('/update-username', requireAuth, async (req, res) => {
854→    const userId = req.userId;
855→    const { username } = req.body;
856→
857→    if (!username || typeof username !== 'string') {
858→        return res.status(400).json({ error: 'username is required' });
859→    }
860→
861→    const trimmed = username.trim();
862→    if (trimmed.length < 3 || trimmed.length > 50) {
863→        return res.status(400).json({ error: 'username must be 3-50 characters' });
864→    }
865→
866→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
867→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
868→    }
869→
870→    const normalized = trimmed.toLowerCase();
871→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
872→    if (RESERVED_WORDS.includes(normalized)) {
873→        return res.status(400).json({ error: 'this username is reserved' });
874→    }
875→
876→    // Check uniqueness
877→    const { data: existing } = await supabase
878→        .from('users')
879→        .select('id')
880→        .ilike('username', normalized)
881→        .neq('id', userId)
882→        .limit(1);
883→
884→    if (existing && existing.length > 0) {
885→        return res.status(409).json({ error: 'username is already taken' });
886→    }
887→
888→    const { error: updateError } = await supabase
889→        .from('users')
890→        .update({ username: trimmed.toLowerCase() })
891→        .eq('id', userId);
892→
893→    if (updateError) {
894→        console.error('update-username error:', updateError.message);
895→        return res.status(500).json({ error: 'failed to update username' });
896→    }
897→
898→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
899→});
